class LmdbAasQueryJoinOrderPlanningTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String AAS = "https://admin-shell.io/aas/3/";
	private static final IRI RDF_TYPE = VF.createIRI("http://www.w3.org/1999/02/22-rdf-syntax-ns#type");
	private static final IRI AAS_SHELL = iri("AssetAdministrationShell");
	private static final IRI ASSET_INFORMATION = iri("assetInformation");
	private static final IRI SPECIFIC_ASSET_ID = iri("specificAssetId");
	private static final IRI SUBMODEL = iri("submodel");
	private static final IRI SUBMODEL_ELEMENT = iri("submodelElement");
	private static final IRI VALUE = iri("value");
	private static final IRI ID_SHORT = iri("idShort");

	private static final String QUERY = """
			PREFIX aas: <https://admin-shell.io/aas/3/>
			SELECT (COUNT(*) AS ?c)
			WHERE {
			  ?aas a aas:AssetAdministrationShell ;
			    aas:assetInformation/aas:specificAssetId [ aas:value "DriveUnit" ] ;
			    aas:submodel/aas:submodelElement/(aas:value)* ?p1 .
			  ?p1 aas:idShort "ratedPower" ;
			      aas:value ?v1 .
			  FILTER (?v1 > 15.0)
			}
			""";

	@Test
	void aasThresholdQueryDoesNotStartWithDisconnectedEndpointCartesianProduct(@TempDir File dataDir)
			throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc");
		config.setSketchEstimatorEnabled(true);
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				loadAasData(connection, 100, 100);
			}
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();

			try (SailRepositoryConnection connection = repository.getConnection()) {
				Explanation explanation = connection.prepareTupleQuery(QUERY).explain(Explanation.Level.Optimized);
				List<StatementPattern> patterns = collectStatementPatterns((TupleExpr) explanation.tupleExpr());
				int driveValueIndex = indexOfDriveUnitValue(patterns);
				int idShortIndex = indexOfIdShortValue(patterns);
				int numericValueIndex = indexOfObjectVar(patterns, VALUE, "v1");
				int pathValueIndex = indexOfObjectVar(patterns, VALUE, "p1");
				int specificAssetIdIndex = indexOfPredicate(patterns, SPECIFIC_ASSET_ID);
				int typeIndex = indexOfPredicate(patterns, RDF_TYPE);

				assertTrue(driveValueIndex >= 0, "Expected optimized AAS query to contain aas:value \"DriveUnit\"");
				assertTrue(idShortIndex >= 0, "Expected optimized AAS query to contain aas:idShort \"ratedPower\"");
				assertTrue(numericValueIndex >= 0, "Expected optimized AAS query to contain aas:value ?v1");
				assertTrue(pathValueIndex >= 0, "Expected optimized AAS query path to contain aas:value ?p1");
				assertTrue(specificAssetIdIndex >= 0, "Expected optimized AAS query to contain aas:specificAssetId");
				assertTrue(typeIndex >= 0, "Expected optimized AAS query to contain rdf:type");
				assertTrue(idShortIndex == 0,
						"AAS threshold query should start from the ratedPower idShort endpoint; "
								+ "statementPatternOrder=" + describe(patterns)
								+ ", firstPatternMetrics=" + describePlannerMetrics(patterns)
								+ "\nPlan:\n" + explanation);
				assertTrue(idShortIndex < driveValueIndex,
						"AAS threshold query should seed from the ratedPower endpoint instead of the DriveUnit "
								+ "component-type endpoint; statementPatternOrder=" + describe(patterns)
								+ ", firstPatternMetrics=" + describePlannerMetrics(patterns)
								+ "\nPlan:\n" + explanation);
				assertTrue(numericValueIndex < pathValueIndex,
						"AAS threshold query should apply the local ratedPower value filter before walking the "
								+ "recursive aas:value path; statementPatternOrder=" + describe(patterns)
								+ ", firstPatternMetrics=" + describePlannerMetrics(patterns)
								+ "\nPlan:\n" + explanation);
				assertTrue(Math.abs(driveValueIndex - specificAssetIdIndex) == 1,
						"AAS threshold query should keep the DriveUnit endpoint next to its specificAssetId bridge; "
								+ "statementPatternOrder=" + describe(patterns)
								+ ", firstPatternMetrics=" + describePlannerMetrics(patterns)
								+ "\nPlan:\n" + explanation);
			}
		} finally {
			repository.shutDown();
		}
	}

	private static void loadAasData(SailRepositoryConnection connection, int driveUnitCount, int sensorCount) {
		for (int i = 0; i < driveUnitCount; i++) {
			addAas(connection, "DriveUnit", "DU-" + i, 20.0d);
		}
		for (int i = 0; i < sensorCount; i++) {
			addAas(connection, "Sensor", "S-" + i, 5.0d);
		}
	}

	private static void addAas(SailRepositoryConnection connection, String componentType, String id,
			double ratedPowerValue) {
		IRI aas = VF.createIRI("urn:aas:" + componentType + ":" + id);
		IRI assetInfo = VF.createIRI("urn:assetInformation:" + componentType + ":" + id);
		IRI specificAsset = VF.createIRI("urn:specificAssetId:" + componentType + ":" + id);
		IRI submodel = VF.createIRI("urn:submodel:" + componentType + ":" + id);
		IRI element = VF.createIRI("urn:submodelElement:" + componentType + ":" + id);
		IRI ratedPower = VF.createIRI("urn:property:ratedPower:" + componentType + ":" + id);
		connection.add(aas, RDF_TYPE, AAS_SHELL);
		connection.add(aas, ASSET_INFORMATION, assetInfo);
		connection.add(assetInfo, SPECIFIC_ASSET_ID, specificAsset);
		connection.add(specificAsset, VALUE, VF.createLiteral(componentType));
		connection.add(aas, SUBMODEL, submodel);
		connection.add(submodel, SUBMODEL_ELEMENT, element);
		connection.add(element, VALUE, ratedPower);
		connection.add(ratedPower, ID_SHORT, VF.createLiteral("ratedPower"));
		connection.add(ratedPower, VALUE, VF.createLiteral(ratedPowerValue));
	}

	private static List<StatementPattern> collectStatementPatterns(TupleExpr tupleExpr) {
		List<StatementPattern> patterns = new ArrayList<>();
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				patterns.add(node);
			}
		});
		return patterns;
	}

	private static int indexOfDriveUnitValue(List<StatementPattern> patterns) {
		for (int i = 0; i < patterns.size(); i++) {
			StatementPattern pattern = patterns.get(i);
			if (VALUE.equals(pattern.getPredicateVar().getValue())
					&& isLiteral(pattern.getObjectVar().getValue(), "DriveUnit")) {
				return i;
			}
		}
		return -1;
	}

	private static int indexOfIdShortValue(List<StatementPattern> patterns) {
		for (int i = 0; i < patterns.size(); i++) {
			StatementPattern pattern = patterns.get(i);
			if (ID_SHORT.equals(pattern.getPredicateVar().getValue())
					&& isLiteral(pattern.getObjectVar().getValue(), "ratedPower")) {
				return i;
			}
		}
		return -1;
	}

	private static int indexOfObjectVar(List<StatementPattern> patterns, IRI predicate, String objectVarName) {
		for (int i = 0; i < patterns.size(); i++) {
			StatementPattern pattern = patterns.get(i);
			if (predicate.equals(pattern.getPredicateVar().getValue())
					&& objectVarName.equals(pattern.getObjectVar().getName())) {
				return i;
			}
		}
		return -1;
	}

	private static int indexOfPredicate(List<StatementPattern> patterns, IRI predicate) {
		for (int i = 0; i < patterns.size(); i++) {
			if (predicate.equals(patterns.get(i).getPredicateVar().getValue())) {
				return i;
			}
		}
		return -1;
	}

	private static boolean isLiteral(Value value, String label) {
		return value instanceof Literal literal && label.equals(literal.getLabel());
	}

	private static String describe(List<StatementPattern> patterns) {
		List<String> descriptions = new ArrayList<>();
		for (StatementPattern pattern : patterns) {
			descriptions.add(pattern.getPredicateVar().getValue() + " -> " + pattern.getObjectVar().getValue());
		}
		return descriptions.toString();
	}

	private static String describePlannerMetrics(List<StatementPattern> patterns) {
		if (patterns.isEmpty()) {
			return "[]";
		}
		StatementPattern first = patterns.getFirst();
		return "{decisionTrace=" + first.getStringMetricPlanned(TelemetryMetricNames.OPTIMIZER_DECISION_TRACE)
				+ ", logicalExploration="
				+ first.getStringMetricPlanned(TelemetryMetricNames.OPTIMIZER_LOGICAL_EXPLORATION)
				+ ", plannedWorkRows=" + first.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS)
				+ "}";
	}

	private static IRI iri(String localName) {
		return VF.createIRI(AAS + localName);
	}
}
